// Avisando os alunos sobre uma prova
function avisoDeProva(): void {
  console.log("Atenção, turma!");
  console.log("Prova de matemática amanhã!");
  console.log("Estudem o capítulo 5.");
}

avisoDeProva();
// Atenção, turma!
// Prova de matemática amanhã!
// Estudem o capítulo 5.

// Previsão do tempo no rádio
function previsaoDoTempo(): void {
  console.log("Bom dia, ouvintes!");
  console.log("Temperatura: 24 graus");
  console.log("Sem previsão de chuva.");
}

previsaoDoTempo();
previsaoDoTempo();
// A mensagem aparece duas vezes — uma chamada por vez

// Separador visual no console
function separador(): void {
  console.log("========================");
}

console.log("Seção 1");
separador();
console.log("Seção 2");
separador();
// Seção 1
// ========================
// Seção 2
// ========================

