// Boletim escolar personalizado
function boletim(aluno: string, nota: number): void {
  console.log(`Aluno: ${aluno}`);
  console.log(`Nota: ${nota}`);
}

boletim("Mariana", 9);
boletim("Pedro", 7);
// Aluno: Mariana → Nota: 9
// Aluno: Pedro → Nota: 7

// Descrevendo o clima de uma cidade
function clima(cidade: string, graus: number): void {
  console.log(`Em ${cidade} faz ${graus} graus hoje.`);
}

clima("Curitiba", 14);
clima("Recife", 31);
clima("São Paulo", 22);
// Em Curitiba faz 14 graus hoje.
// Em Recife faz 31 graus hoje.
// Em São Paulo faz 22 graus hoje.

// Calculando o preço total de um produto
function mostrarPreco(produto: string, preco: number, qtd: number): void {
  console.log(`${produto}: R$${preco * qtd}`);
}

mostrarPreco("Caderno", 15, 3);
mostrarPreco("Caneta", 4, 10);
// Caderno: R$45
// Caneta: R$40

