// Função que retorna a média de duas notas
function mediaNotas(nota1: number, nota2: number): number {
  return (nota1 + nota2) / 2;
}

const minhaMedia: number = mediaNotas(8, 10);
console.log(`Média: ${minhaMedia}`);
// Média: 9

// Usando o resultado direto em outra expressão
function areaRetangulo(largura: number, altura: number): number {
  return largura * altura;
}

console.log(`Área: ${areaRetangulo(5, 3)} m²`);

const areaTotal: number = areaRetangulo(5, 3) + areaRetangulo(2, 4);
console.log(`Área total: ${areaTotal} m²`);
// Área: 15 m²
// Área total: 23 m²

// Função com múltiplos return em caminhos diferentes
function classificarNota(nota: number): string {
  if (nota >= 9) {
    return "Excelente";
  } else if (nota >= 7) {
    return "Bom";
  } else {
    return "Precisa melhorar";
  }
}

console.log(classificarNota(10));
console.log(classificarNota(7));
console.log(classificarNota(4));
// Excelente
// Bom
// Precisa melhorar

// return encerra a função imediatamente
function verificarIdade(idade: number): string {
  if (idade < 0) {
    return "Idade inválida";
  }
  return `Você tem ${idade} anos`;
}

console.log(verificarIdade(-5));
console.log(verificarIdade(12));
// Idade inválida
// Você tem 12 anos

// Retornando boolean — perguntas de sim/não
function estáCalor(temperatura: number): boolean {
  return temperatura > 30;
}

console.log(estáCalor(35));
console.log(estáCalor(18));
// true
// false

// Diferença entre return e console.log
function comReturn(n: number): number {
  return n * 2;
}

function comLog(n: number): void {
  console.log(n * 2);
}

const resultado: number = comReturn(5);
console.log(resultado + 10);
// 20 (10 + 10 — pôde usar o valor retornado)

comLog(5);
// 10 (aparece na tela, mas não dá pra guardar ou usar)

// Retorno boolean — verificação
function ehAprovado(nota: number): boolean {
  return nota >= 6;
}

console.log(ehAprovado(8));
console.log(ehAprovado(4));
// true
// false

// Retorno string — formatação
function formatarNota(aluno: string, nota: number): string {
  return `${aluno}: nota ${nota}`;
}

console.log(formatarNota("Ana", 9));
console.log(formatarNota("Bruno", 7));
