// Vários parâmetros com tipos diferentes
function criarMensagem(remetente: string, destinatario: string, urgente: boolean): string {
  if (urgente) {
    return `URGENTE: ${remetente} para ${destinatario}`;
  }
  return `${remetente} para ${destinatario}`;
}

console.log(criarMensagem("Ana", "Bruno", true));
console.log(criarMensagem("Clara", "Diego", false));
// URGENTE: Ana para Bruno
// Clara para Diego

