// As 3 formas lado a lado

// 1. Tradicional
function triploTradicional(n: number): number {
  return n * 3;
}

// 2. Arrow com chaves
const triploArrow = (n: number): number => {
  return n * 3;
};

// 3. Arrow curta (sem chaves, sem return)
const triploCurta = (n: number): number => n * 3;

console.log(triploTradicional(4));
console.log(triploArrow(4));
console.log(triploCurta(4));
// 12, 12, 12 — todas fazem o mesmo

// Arrow functions com string
const saudar = (nome: string): string => `Olá, ${nome}!`;

console.log(saudar("Beatriz"));
console.log(saudar("Lucas"));
// Olá, Beatriz!
// Olá, Lucas!

// Arrow function que retorna boolean
const ehPositivo = (n: number): boolean => n > 0;

console.log(ehPositivo(5));
console.log(ehPositivo(-3));
console.log(ehPositivo(0));
// true
// false
// false

// Arrow com múltiplos parâmetros
const somarTres = (a: number, b: number, c: number): number => a + b + c;

console.log(somarTres(1, 2, 3));
console.log(somarTres(10, 20, 30));
// 6
// 60

// Quando NÃO dá pra usar a versão curta (precisa de chaves)
const classificar = (nota: number): string => {
  if (nota >= 7) {
    return "Aprovado";
  } else {
    return "Reprovado";
  }
};

console.log(classificar(8));
console.log(classificar(5));
// Aprovado
// Reprovado

// Arrow function void (sem retorno)
const exibir = (mensagem: string): void => {
  console.log(`>> ${mensagem}`);
};

exibir("Carregando...");
exibir("Pronto!");
// >> Carregando...
// >> Pronto!

// Função simples com um parâmetro e return
function metade(n: number): number {
  return n / 2;
}

console.log(metade(10));
console.log(metade(7));
// 5
// 3.5

// Função com dois parâmetros
function multiplicar(a: number, b: number): number {
  return a * b;
}

console.log(multiplicar(4, 5));
console.log(multiplicar(3, 7));
// 20
// 21

// Média de dois números (mais simples que a de três)
function mediaDois(a: number, b: number): number {
  return (a + b) / 2;
}

console.log(mediaDois(8, 10));
// 9

// Erro de precedência: SEM parênteses
function mediaErrada(a: number, b: number, c: number): number {
  return a + b + c / 3;
}

console.log(mediaErrada(6, 6, 6));
// 14 ← ERRADO! Deveria ser 6
// Porque fez: 6 + 6 + (6/3) = 6 + 6 + 2 = 14

// Erro de precedência: COM parênteses (correto)
function mediaCerta(a: number, b: number, c: number): number {
  return (a + b + c) / 3;
}

console.log(mediaCerta(6, 6, 6));
// 6 ← CORRETO! (6+6+6)/3 = 18/3 = 6

// Erro: usando console.log em vez de return
function dobrarErrado(n: number): void {
  console.log(n * 2);
}

const resultado = dobrarErrado(5);
console.log(resultado);
// 10 ← isso aparece do console.log interno
// undefined ← a função não retornou nada!

// Classificando notas por faixa (mesmo padrão)
function classificarNota(nota: number): string {
  if (nota < 4) {
    return "Insuficiente";
  } else if (nota < 7) {
    return "Regular";
  } else {
    return "Bom";
  }
}

console.log(classificarNota(3));
console.log(classificarNota(6));
console.log(classificarNota(9));
// Insuficiente
// Regular
// Bom

// Usando .length para contar caracteres
console.log("abc".length);
console.log("abc12345".length);
console.log("senhaForte123".length);
// 3
// 8
// 13

// Erro: usando <= em vez de < (muda os limites)
function validarErrada(senha: string): string {
  if (senha.length <= 6) {
    return "Fraca";
  } else if (senha.length <= 9) {
    return "Média";
  } else {
    return "Forte";
  }
}

console.log(validarErrada("123456"));
// Fraca ← ERRADO! 6 caracteres deveria ser "Média"
// Com < 6 em vez de <= 6, o resultado seria correto

// Versão sem else (funciona porque return encerra)
function validarSemElse(senha: string): string {
  if (senha.length < 6) return "Fraca";
  if (senha.length < 10) return "Média";
  return "Forte";
}

console.log(validarSemElse("ab"));
console.log(validarSemElse("abcdef"));
console.log(validarSemElse("abcdefghij"));
// Fraca
// Média
// Forte

// Classificando velocidade de internet (mesmo padrão)
function classificarVelocidade(mbps: number): string {
  if (mbps < 10) {
    return "Lenta";
  } else if (mbps < 100) {
    return "Normal";
  } else {
    return "Rápida";
  }
}

console.log(classificarVelocidade(5));
console.log(classificarVelocidade(50));
console.log(classificarVelocidade(200));
// Lenta
// Normal
// Rápida

// Testando os limites exatos das faixas
function testarLimites(senha: string): void {
  console.log(`"${senha}" (${senha.length} chars)`);
}

testarLimites("12345");
testarLimites("123456");
testarLimites("123456789");
testarLimites("1234567890");
// "12345" (5 chars) → Fraca (< 6)
// "123456" (6 chars) → Média (>= 6, < 10)
// "123456789" (9 chars) → Média (>= 6, < 10)
// "1234567890" (10 chars) → Forte (>= 10)

// Versão simplificada: só soma e subtração
function calcSimples(a: number, b: number, op: string): number {
  if (op === "+") {
    return a + b;
  } else if (op === "-") {
    return a - b;
  } else {
    return 0;
  }
}

console.log(calcSimples(5, 3, "+"));
console.log(calcSimples(5, 3, "-"));
console.log(calcSimples(5, 3, "x"));
// 8
// 2
// 0

// O ERRO: comparar sem aspas
// if (operacao === +) ← ERRADO! + sem aspas é operador
// if (operacao === "+") ← CORRETO! "+" com aspas é string

const simbolo: string = "+";
console.log(simbolo === "+");
// true — comparação correta de strings

// Testando com divisão (resultado decimal)
function dividir(a: number, b: number): number {
  return a / b;
}

console.log(dividir(10, 3));
console.log(dividir(10, 5));
// 3.3333333333333335
// 2
// TypeScript lida com decimais automaticamente

// Dispatch completo com todas as operações
function calc(a: number, b: number, op: string): number {
  if (op === "+") return a + b;
  else if (op === "-") return a - b;
  else if (op === "*") return a * b;
  else if (op === "/") return a / b;
  else return 0;
}

console.log(calc(10, 3, "+"));
console.log(calc(10, 3, "-"));
console.log(calc(10, 3, "*"));
console.log(calc(10, 3, "/"));
console.log(calc(10, 3, "?"));
// 13, 7, 30, 3.33..., 0

// Usando a função calcular para montar uma expressão
function mostrarCalculo(a: number, b: number, op: string): void {
  if (op === "+") {
    console.log(`${a} + ${b} = ${a + b}`);
  } else if (op === "-") {
    console.log(`${a} - ${b} = ${a - b}`);
  }
}

mostrarCalculo(15, 8, "+");
mostrarCalculo(15, 8, "-");
// 15 + 8 = 23
// 15 - 8 = 7

// Conceito: parâmetro string como seletor
function executar(acao: string): string {
  if (acao === "ligar") return "Ligando...";
  else if (acao === "desligar") return "Desligando...";
  else return "Ação desconhecida";
}

console.log(executar("ligar"));
console.log(executar("desligar"));
console.log(executar("pausar"));
// Ligando...
// Desligando...
// Ação desconhecida

// void: a função não retorna valor
function avisar(): void {
  console.log("Aviso importante!");
}

avisar();
const resultado = avisar();
console.log(resultado);
// Aviso importante!
// Aviso importante!
// undefined ← void não devolve nada

// return: encerra a função, não o programa
function verificar(n: number): string {
  if (n > 0) return "Positivo";
  return "Não positivo";
}

console.log(verificar(5));
console.log("O programa continua aqui!");
// Positivo
// O programa continua aqui! ← o return não parou o programa

// Arrow curta: sem { } e sem return
const quadrado = (n: number): number => n * 2;

// É o mesmo que:
const quadradoLongo = (n: number): number => {
  return n * 2;
};

console.log(quadrado(4));
console.log(quadradoLongo(4));
// 8
// 8

// Parâmetro vs. outros conceitos
function exemplo(entrada: number): number {
  return entrada * 3;
}

// "exemplo" → nome da função
// "entrada" → parâmetro (variável que recebe valores)
// ": number" no parâmetro → tipo do parâmetro
// ": number" no retorno → tipo do retorno
// "entrada * 3" → expressão retornada

console.log(exemplo(10));
// 30

// Todos os conceitos juntos num exemplo
const ehPar = (n: number): boolean => n % 2 === 0;

function listarPares(limite: number): void {
  for (let i: number = 1; i <= limite; i++) {
    if (ehPar(i)) {
      console.log(i);
    }
  }
}

listarPares(8);
// 2, 4, 6, 8

// Revisão: function vs arrow
function somar1(a: number, b: number): number {
  return a + b;
}

const somar2 = (a: number, b: number): number => a + b;

console.log(somar1(3, 4));
console.log(somar2(3, 4));
// 7
// 7 — mesmo resultado, sintaxes diferentes
